from string_utils.generation import roman_range as correct_roman_range
from mutant.string_utils.generation import roman_range as mutant_roman_range

# Test input values where an overflow error is expected in valid code but may not be in mutant
try:
    correct_roman_range(5, start=7, step=-1)
    print("Correct code did not raise an OverflowError when it should have.")
except OverflowError as e:
    print(f"Correct code raised OverflowError: {e}")

try:
    mutant_roman_range(5, start=7, step=-1)
    print("Mutant code did not raise an OverflowError when it should have.")
except OverflowError as e:
    print(f"Mutant code raised OverflowError: {e}")

